  3	
  4	import {
  5	  type Modify,
  6	  type OpenShiftNetworkAttachmentDefinition,
  7	  ProviderModel,
  8	  type V1beta1Provider,
  9	} from '@kubev2v/types';
 10	import { type K8sModel, k8sPatch } from '@openshift-console/dynamic-plugin-sdk';
 11	import {
 12	  Dropdown,
 13	  DropdownItem,
 14	  DropdownList,
 15	  MenuToggle,
 16	  type MenuToggleElement,
 17	} from '@patternfly/react-core';
 18	import { DEFAULT_NETWORK } from '@utils/constants';
 19	
 20	import useProviderInventory from '../../hooks/useProviderInventory';
 21	import { EditModal } from '../EditModal/EditModal';
 22	import type {
 23	  EditModalProps,
 24	  ModalInputComponentType,
 25	  OnConfirmHookType,
 26	} from '../EditModal/types';
 27	
 28	/**
 29	 * Handles the confirmation action for editing a resource annotations.
 30	 * Adds or updates the 'forklift.konveyor.io/defaultTransferNetwork' annotation in the resource's metadata.
 31	 *
 32	 * @param {Object} options - Options for the confirmation action.
 33	 * @param {Object} options.resource - The resource to be modified.
 34	 * @param {Object} options.model - The model associated with the resource.
 35	 * @param {any} options.newValue - The new value for the 'forklift.konveyor.io/defaultTransferNetwork' annotation.
 36	 * @returns {Promise<Object>} - The modified resource.
 37	 */
 38	const onConfirm: OnConfirmHookType = async ({ model, newValue: value, resource }) => {
 39	  const currentAnnotations = resource?.metadata?.annotations;
 40	  const newAnnotations = {
 41	    ...currentAnnotations,
 42	    'forklift.konveyor.io/defaultTransferNetwork': value ?? undefined,
 43	  };
 44	
 45	  const op = resource?.metadata?.annotations ? 'replace' : 'add';
 46	
 47	  const obj = await k8sPatch({
 48	    data: [
 49	      {
 50	        op,
 51	        path: '/metadata/annotations',
 52	        value: newAnnotations,
 53	      },
 54	    ],
 55	    model: model!,
 56	    resource,
 57	  });
 58	
 59	  return obj;
 60	};
 61	
 62	type DropdownRendererProps = {
 63	  value: string | number;
 64	  onChange: (value: string | number) => void;
 65	};
 66	
 67	/**
 68	 * Extracts the network name from a string. The input string can be of the form 'name' or 'namespace/name'.
 69	 *
 70	 * @param {string} value - The input string from which the network name is to be extracted.
 71	 * @returns {string} The network name extracted from the input string.
 72	 */
 73	const getNetworkName = (value: string | number): string => {
 74	  if (!value || typeof value !== 'string') {
 75	    return DEFAULT_NETWORK;
 76	  }
 77	
 78	  const parts = value.split('/');
 79	
 80	  return parts[parts.length - 1];
 81	};
 82	
 83	const OpenshiftNetworksInputFactory: ({
 84	  resource,
 85	}: {
 86	  resource: V1beta1Provider;
 87	}) => ModalInputComponentType = ({ resource: provider }) => {
 88	  const DropdownRenderer: FC<DropdownRendererProps> = ({ onChange, value }) => {
 89	    // Hook for managing the open/close state of the dropdown
 90	    const [isOpen, setIsOpen] = useState(false);
 91	
 92	    const onToggleClick = () => {
 93	      setIsOpen((isDropdownOpen) => !isDropdownOpen);
 94	    };
 95	
 96	    const onSelect = (_event: MouseEvent | undefined, _value: string | number | undefined) => {
 97	      setIsOpen(false);
 98	    };
 99	
100	    const { inventory: networks } = useProviderInventory<OpenShiftNetworkAttachmentDefinition[]>({
101	      provider,
102	      subPath: 'networkattachmentdefinitions?detail=4',
103	    });
104	
105	    const name = getNetworkName(value);
106	
107	    const dropdownItems = [
108	      <DropdownItem
109	        value={0}
110	        key={DEFAULT_NETWORK}
111	        description={DEFAULT_NETWORK}
112	        onClick={() => {
113	          onChange('');
114	        }}
115	      >
116	        {DEFAULT_NETWORK}
117	      </DropdownItem>,
118	      ...(networks ?? []).map((network) => (
119	        <DropdownItem
120	          value={1}
121	          key={network.name}
122	          description={network.namespace}
123	          onClick={() => {
124	            onChange(`${network.namespace}/${network.name}`);
125	          }}
126	        >
127	          {network.name}
128	        </DropdownItem>
129	      )),
130	    ];
131	
132	    return (
133	      <Dropdown
134	        isOpen={isOpen}
135	        onOpenChange={setIsOpen}
136	        onSelect={onSelect}
137	        toggle={(toggleRef: Ref<MenuToggleElement>) => (
138	          <MenuToggle
139	            ref={toggleRef}
140	            onClick={onToggleClick}
141	            isExpanded={isOpen}
142	            variant={'default'}
143	          >
144	            {name}
145	          </MenuToggle>
146	        )}
147	        shouldFocusToggleOnSelect
148	        popperProps={{
149	          position: 'right',
150	        }}
151	        isScrollable={true}
152	      >
153	        <DropdownList>{dropdownItems}</DropdownList>
154	      </Dropdown>
155	    );
156	  };
157	
158	  return DropdownRenderer;
159	};
160	
161	const EditProviderDefaultTransferNetworkInternal: FC<EditProviderDefaultTransferNetworkProps> = (
162	  props,
163	) => {
164	  const { t } = useForkliftTranslation();
165	
166	  return (
167	    <EditModal
168	      {...props}
169	      jsonPath={['metadata', 'annotations', 'forklift.konveyor.io/defaultTransferNetwork']}
170	      title={props?.title ?? t('Edit default transfer network')}
171	      label={props?.label ?? t('Default transfer network')}
172	      helperText={t('Please choose a NetworkAttachmentDefinition for default data transfer.')}
173	      model={ProviderModel}
174	      onConfirmHook={onConfirm}
175	      body={t(
176	        `You can select a default migration network for an OpenShift Virtualization provider in the Red Hat OpenShift web console to improve performance.
177	        The default migration network is used to transfer disks to the namespaces in which it is configured.If you do not select a migration network,
178	        the default migration network is the pod network, which might not be optimal for disk transfer.`,
179	      )}
180	      InputComponent={OpenshiftNetworksInputFactory({ resource: props.resource })}
181	    />
182	  );
183	};
184	
185	type EditProviderDefaultTransferNetworkProps = Modify<
186	  EditModalProps,
187	  {
188	    resource: V1beta1Provider;
189	    title?: string;
190	    label?: string;
191	    model?: K8sModel;
192	    jsonPath?: string | string[];
193	  }
194	>;
195	
196	export const EditProviderDefaultTransferNetwork: FC<EditProviderDefaultTransferNetworkProps> = (
197	  props,
198	) => {
199	  if (props.resource?.spec?.type !== 'openshift') {
200	    return <></>;
201	  }
202	
203	  return <EditProviderDefaultTransferNetworkInternal {...props} />;
204	};

